function daysFromNow(n){ return new Date(Date.now()+n*86400000).toISOString().split("T")[0]; }
function minutesAgo(n) { return new Date(Date.now()-n*60000).toISOString(); }
function getExpiry(d){
  if (!d) return "fresh";
  const diff = Math.ceil((new Date(d)-new Date())/86400000);
  return diff<0?"expired":diff<=3?"soon":"fresh";
}
function fmtDate(d){
  if (!d) return "未設定";
  const dt=new Date(d); return `${dt.getMonth()+1}月${dt.getDate()}日`;
}
function relTime(iso){
  const m=Math.round((Date.now()-new Date(iso))/60000);
  return m<1?"たった今":m<60?`${m}分前`:m<1440?`${Math.floor(m/60)}時間前`:`${Math.floor(m/1440)}日前`;
}

